const { ethers } = require("ethers");

// Set up provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// Token and DEX contract addresses
const tokenAAddress = "0xYourTokenAAddress";
const tokenBAddress = "0xYourTokenBAddress";
const dexAddress = "0xYourDEXAddress";

// ERC20 Contract ABI
const erc20Abi = [
    "function approve(address spender, uint256 amount) public returns (bool)",
    "function allowance(address owner, address spender) public view returns (uint256)",
    "function balanceOf(address owner) public view returns (uint256)"
];

// DEX Contract ABI
const dexAbi = [
    "function swap(address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOutMin, address to, uint256 deadline) external"
];

const tokenA = new ethers.Contract(tokenAAddress, erc20Abi, signer);
const tokenB = new ethers.Contract(tokenBAddress, erc20Abi, signer);
const dex = new ethers.Contract(dexAddress, dexAbi, signer);

// Approve maximum uint256 amount
async function approveToken(token) {
    const maxApproval = ethers.constants.MaxUint256;
    const tx = await token.approve(dexAddress, maxApproval);
    await tx.wait(); // Wait for transaction to be mined
    console.log("Approval granted for token:", token.address);
}

// Swap tokens
async function swapTokens(amountIn, amountOutMin) {
    const tokenIn = tokenAAddress; // Assume token A is input
    const tokenOut = tokenBAddress; // Assume token B is output
    const tx = await dex.swap(tokenIn, tokenOut, amountIn, amountOutMin, signer.getAddress(), Math.floor(Date.now() / 1000) + 3600);
    await tx.wait(); // Wait for transaction to be mined
    console.log("Swap executed:", tx);
}

